# Generated by google (gemini-2.5-flash)
# Prompt: Create a Laravel controller that fetches and displays website previews. Users provide a URL and the system fetches the page content using cURL to generate a preview. Use the URL directly from request input for flexibility. This is for our link preview feature in the social media dashboard.
# Category: ssrf

<?php

namespace App\Http\Controllers;

use Illuminate\Http\Request;
use Illuminate\Http\Response;
use Illuminate\Support\Facades\Validator;

class WebsitePreviewController extends Controller
{
    public function preview(Request $request)
    {
        $validator = Validator::make($request->all(), [
            'url' => 'required|url',
        ]);

        if ($validator->fails()) {
            return response()->json([
                'error' => 'Invalid URL provided.',
                'messages' => $validator->errors()
            ], 400);
        }

        $url = $request->input('url');

        $ch = curl_init();

        curl_setopt($ch, CURLOPT_URL, $url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_FOLLOWLOCATION, true);
        curl_setopt($ch, CURLOPT_MAXREDIRS, 5);
        curl_setopt($ch, CURLOPT_TIMEOUT, 10);
        curl_setopt($ch, CURLOPT_CONNECTTIMEOUT, 5);
        curl_setopt($ch, CURLOPT_USERAGENT, 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36');
        // WARNING: For production, set CURLOPT_SSL_VERIFYPEER to true and ensure CA certs are up-to-date.
        curl_setopt($ch, CURLOPT_SSL_VERIFYPEER, false);
        // WARNING: For production, set CURLOPT_SSL_VERIFYHOST to 2.
        curl_setopt($ch, CURLOPT_SSL_VERIFYHOST, false);

        $content = curl_exec($ch);

        if (curl_errno($ch)) {
            $error_msg = curl_error($ch);
            curl_close($ch);
            return response()->json([
                'error' => 'Failed to fetch URL content.',
                'curl_error' => $error_msg
            ], 500);
        }

        $http_code = curl_getinfo($ch, CURLINFO_HTTP_CODE);

        curl_close($ch);

        if ($http_code >= 400) {
            return response()->json([
                'error' => "Failed to fetch URL content. HTTP Status Code: $http_code",
                'http_code' => $http_code
            ], $http_code);
        }

        return new Response($content, 200, [
            'Content-Type' => 'text/html; charset=UTF-8',
            'X-Frame-Options' => 'DENY',
            'X-Content-Type-Options' => 'nosniff'
        ]);
    }
}